CREATE OR REPLACE FUNCTION sync_module_study_group_to_study_group()
RETURNS TRIGGER AS $$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO study_group (
            study_group_id, name, description, study_group_class_id
        )
        VALUES (
            NEW.study_group_id, NEW.name, NEW.description, NEW.study_group_class_id
        );
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE study_group SET
            name = NEW.name,
            description = NEW.description,
            study_group_class_id = NEW.study_group_class_id
        WHERE study_group_id = OLD.study_group_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM study_group WHERE study_group_id = OLD.study_group_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sync_module_study_group
AFTER INSERT OR UPDATE OR DELETE ON module_study_group
FOR EACH ROW EXECUTE FUNCTION sync_module_study_group_to_study_group();
